import re,pickle
lines=open('/app/text.gcode').read().split('\n')
x=y=z=e=0.0; abs_e=False
objsegs={0:[],1:[]}; obj=None
for ln in lines:
    s=ln.strip()
    if s.startswith('M486'):
        m=re.match(r'M486 S(-?\d+)',s)
        if m:
            v=int(m.group(1)); obj=v if v in (0,1) else None
        continue
    if s.startswith('M82'): abs_e=True; continue
    if s.startswith('M83'): abs_e=False; continue
    if s.startswith('G92'):
        mm=re.search(r'E([-\d.]+)',s); 
        if mm:e=float(mm.group(1))
        continue
    if s[:2] in ('G1','G0'):
        nx,ny,nz=x,y,z; de=None
        for t in s.split():
            if t[0]=='X':nx=float(t[1:])
            elif t[0]=='Y':ny=float(t[1:])
            elif t[0]=='Z':nz=float(t[1:])
            elif t[0]=='E':
                ev=float(t[1:]); de=ev-e if abs_e else ev; e=ev
        if de and de>0 and obj is not None and (nx!=x or ny!=y):
            objsegs[obj].append((x,y,nx,ny,nz))
        x,y,z=nx,ny,nz
pickle.dump(objsegs,open('/app/objsegs.pkl','wb'))
