    xs=[s[0] for s in v]+[s[2] for s in v]
    ys=[s[1] for s in v]+[s[3] for s in v]
    zs=[s[4] for s in v]
    print(k,len(v),"x",round(min(xs),1),round(max(xs),1),"y",round(min(ys),1),round(max(ys),1),"z",round(min(zs),1),round(max(zs),1))
